fun solve(s: String): Long {
    val n = s.length
    var costT0 = 0 // Cost for "010101..."
    var costT1 = 0 // Cost for "101010..."
    var costAll0 = 0 // Cost for "000000..."
    var costAll1 = 0 // Cost for "111111..."

    for (i in 0 until n) {
        val charS = s[i]

        // T0: 0 at even indices, 1 at odd indices
        val targetT0 = if (i % 2 == 0) '0' else '1'
        if (charS != targetT0) {
            costT0++
        }

        // T1: 1 at even indices, 0 at odd indices
        val targetT1 = if (i % 2 == 0) '1' else '0'
        if (charS != targetT1) {
            costT1++
        }

        // All 0s
        if (charS == '1') {
            costAll0++
        }

        // All 1s
        if (charS == '0') {
            costAll1++
        }
    }

    return minOf(costT0, costT1, costAll0, costAll1).toLong()
}
